var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"해적이 할 수 있는 가장 낭만적인 일이 뭘까요?","JPN":" 海賊にできる一番ロマンチックなこととはなんでしょう？","ENG":"What's the ultimate pirate dream?","TWN":"身為一個海盜，最浪漫的事是什麼呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"바로 자신이 하고 싶은 일을 꺼리낌없이 하는 거겠죠!","JPN":" それは、自分がやりたいことを何の躊躇いもなくすることですわ！","ENG":"It's doing whatever you want without hesitation!","TWN":"就是可以肆無忌憚地做自己想做的事！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그 이름하여...! 선상반란!","JPN":" その名も……！　船上反乱！","ENG":"I call it..! Mutiny on board!","TWN":"這件事就是…！船上造反！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네? 지금 선장님에게 불만이 있냐고요?","JPN":" はい？　今の船長に不満があるのかって？","ENG":"Huh? Do I have any dissatisfaction with our captain?","TWN":"嗯？我是不是對船長有什麼不滿？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"으음- 드라코 선장은 좋은 사람이에요. 너무 좋은 사람이라서 문제죠.","JPN":" うーん、ドラコ船長はいい人です。人が良すぎて問題ですわ。","ENG":"Mm... Captain Dracasia is a good person. But sometimes to a fault.","TWN":"這個嘛，德拉克船長是個好人，但問題就是人太好。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저는 무자비함과 때를 가리지 않는 추진력이 해적의 덕목이라 생각하거든요.","JPN":" 私は無慈悲と時をわきまえない推進力が海賊のたしなみだと思ってますの。","ENG":"In my opinion, a pirate should possess a more vicious and unrelenting spirit.","TWN":"我認為心狠手辣和毫無顧忌是海盜的品格。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그런데 저희 선장님은 너무 지나치게 신중하고 이성적이에요!","JPN":" でも、私たちの船長は慎重すぎて理性的です！","ENG":"However, our captain is excessively cautious and logical!","TWN":"但我們的船長過於理性謹慎。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"탈리? 참아- 탈리? 기다려- 실내에선 쏘면 안돼- 돈가방 든 녀석은 쏘면 안돼- 빨간 연료통도 쏘면 안돼-","JPN":" タリー？　我慢しろよ～　タリー？　待て～室内で撃っちゃダメだ～お金のカバンを持った奴は撃っちゃダメだ～赤い燃料タンクも撃っちゃダメだ～","ENG":"Tallie? No. Tallie? Wait. You can't fire it indoors. Don't shoot the guy with the money bag. No, you can't shoot at the red fuel tank.","TWN":"塔莉？你忍忍。塔莉？先等等。不行在室內開砲，不行對拿錢包的人開砲，也不行對紅色燃料桶開砲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐만 하면 안돼, 안돼, 안돼...!","JPN":" なんでもかんでもダメ、ダメ、ダメ……！","ENG":"She says no to everything...!","TWN":"什麼都不行不行不行…！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그래서 저는 더 이상 참지 않기로 했어요! 누구의 명령도 듣지 않고 제 맘대로 쏘고 싶다고요!","JPN":" ですので、私はもう我慢しないことにしましたわ！　誰の命令も聞かずに、自分勝手に撃ちたいです！","ENG":"That's why I decided not to hold it in anymore! I don't want to listen to anyone, and I'm gonna fire whenever I want!","TWN":"所以我決定不再忍受她！我想要盡情地開砲，不受任何人的指揮！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"새 선장? 앗...! 그러게요. 제가 선장을 꺾어버리면 누군가는 선장을 대신 맡아야 하는 거였죠? 난 선장은 귀찮아서 싫은데…","JPN":" 新しい船長？　あっ……！　そうですわね。私が船長に勝つと、誰かは代わりに船長にならないといけないですか。私、船長は面倒くさくて嫌なのですけど……","ENG":"The new captain? Oh...! You're right. If I beat our current captain, someone else has to take over, right? But I'm not interested in being the captain...","TWN":"新任船長？對吼…！我把現任船長扳倒的話，誰來當下一任船長？當船長好麻煩，我才不想…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"...아!","JPN":" ……あ！","ENG":"...Oh!","TWN":"…有啦！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"이 참에 당신이 선장이 되어보는 건 어때요? 반란이 성공하면 제가 당신에게 선장 자릴 드릴게요! 두 번 다신 없을 기회라고요?","JPN":" この際にあなたが船長になってみるのはどうでしょう？　反乱に成功すると、私があなたに船長の職をあげますわ！　二度とないチャンスです！","ENG":"How about you become my captain? Once my rebellion is successful, I'll make you the captain! It's an opportunity of a lifetime, you know?","TWN":"你乾脆趁這個機會當當看船長吧？造反成功後，我會把船長的位置讓給你！這可是絕佳的好機會喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};